CREATE OR REPLACE FUNCTION OFSERM.Market_Risk_Measures_Mduration(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    MERGE  INTO FCT_MARKET_RISK_EXPOSURES TT USING (   SELECT * FROM (  SELECT  /*+ PARALLEL(4) */ FCT_MARKET_RISK_EXPOSURES.N_ACCT_SKEY,FCT_MARKET_RISK_EXPOSURES.N_RUN_SKEY,FCT_MARKET_RISK_EXPOSURES.N_GAAP_SKEY,FCT_MARKET_RISK_EXPOSURES.N_MIS_DATE_SKEY,(FCT_MARKET_RISK_EXPOSURES.N_MDURATION) AS  T_2498138759828_0,   (CASE  WHEN  ( ((1=1)) ) THEN 10 ELSE 11 END)  AS COND_2498138759828_10 ,  (CASE WHEN 1=1 THEN FSI_SETUP_MR_INPUT_MEASURES.N_MDURATION ELSE NULL END ) AS EXP_2498138759828_10,(FCT_MARKET_RISK_EXPOSURES.N_MDURATION) AS EXP_2498138759828_11 ,(FCT_MARKET_RISK_EXPOSURES.N_POST_OFFSET_EXP_AMT) AS  T_2498138759828_1,   (CASE  WHEN  ( ((1=1)) ) THEN 20 ELSE 21 END)  AS COND_2498138759828_20 ,  (coalesce(CASE WHEN 1=1 THEN FSI_SETUP_MR_INPUT_MEASURES.N_POST_OFFSET_EXP_AMT_NPV ELSE NULL END ,CASE WHEN 1 = 1 THEN FCT_MARKET_RISK_EXPOSURES.n_post_offset_exp_amt ELSE NULL END )) AS EXP_2498138759828_20,(FCT_MARKET_RISK_EXPOSURES.N_POST_OFFSET_EXP_AMT) AS EXP_2498138759828_21 ,(FCT_MARKET_RISK_EXPOSURES.N_EXPOSURE_AMT) AS  T_2498138759828_2,   (CASE  WHEN  ( ((1=1)) ) THEN 30 ELSE 31 END)  AS COND_2498138759828_30 ,  (coalesce(CASE WHEN 1=1 THEN FSI_SETUP_MR_INPUT_MEASURES.N_EXPOSURE_AMT_NPV ELSE NULL END ,CASE WHEN 1 = 1 THEN FCT_MARKET_RISK_EXPOSURES.n_exposure_amt ELSE NULL END )) AS EXP_2498138759828_30,(FCT_MARKET_RISK_EXPOSURES.N_EXPOSURE_AMT) AS EXP_2498138759828_31  FROM  FCT_MARKET_RISK_EXPOSURES INNER JOIN DIM_RUN ON FCT_MARKET_RISK_EXPOSURES.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY INNER JOIN DIM_DATES ON DIM_DATES.N_DATE_SKEY = FCT_MARKET_RISK_EXPOSURES.N_MIS_DATE_SKEY INNER JOIN DIM_EXPOSURE ON DIM_EXPOSURE.N_ACCT_SKEY = FCT_MARKET_RISK_EXPOSURES.N_ACCT_SKEY LEFT OUTER JOIN FSI_SETUP_MR_INPUT_MEASURES ON DIM_EXPOSURE.V_EXPOSURE_ID = FSI_SETUP_MR_INPUT_MEASURES.V_INSTRUMENT_CODE AND FSI_SETUP_MR_INPUT_MEASURES.FIC_MIS_DATE = DIM_DATES.FIC_MIS_DATE   WHERE (1=1)  AND (DIM_DATES.D_CALENDAR_DATE=TO_DATE('20260331','yyyymmdd') AND DIM_RUN.n_run_skey = '870')  ) WHERE (   (COND_2498138759828_10 <> 11)   OR  (COND_2498138759828_20 <> 21)  OR  (COND_2498138759828_30 <> 31) ) ) SS ON ( TT.N_ACCT_SKEY= SS.N_ACCT_SKEY AND TT.N_RUN_SKEY= SS.N_RUN_SKEY AND TT.N_GAAP_SKEY= SS.N_GAAP_SKEY AND TT.N_MIS_DATE_SKEY= SS.N_MIS_DATE_SKEY) WHEN MATCHED THEN UPDATE SET  TT.N_MDURATION=  CASE  WHEN  COND_2498138759828_10=10 THEN EXP_2498138759828_10 ELSE EXP_2498138759828_11 END  , TT.N_POST_OFFSET_EXP_AMT=  CASE  WHEN  COND_2498138759828_20=20 THEN EXP_2498138759828_20 ELSE EXP_2498138759828_21 END  , TT.N_EXPOSURE_AMT=  CASE  WHEN  COND_2498138759828_30=30 THEN EXP_2498138759828_30 ELSE EXP_2498138759828_31 END;

    COMMIT;
    RETURN 'OK';

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        RETURN 'FAIL: ' || SQLERRM;
END;
/
